#!/usr/bin/env python3
"""
Generate a self-contained HTML QC report for one project, aggregating
across every plate/library that contributed samples to it.

Usage:
    project_report.py --h5ad ProjectX.h5ad --project ProjectX --output ProjectX_report.html
"""
import argparse
import base64
import io

import anndata as ad
import matplotlib
matplotlib.use("Agg")
import matplotlib.pyplot as plt
import scanpy as sc

# RNATOR banner (gator mascot + wordmark + tagline) cropped directly
# from the actual repo README banner image, not a recreation.
BANNER_B64 = ""

# RNATOR brand palette -- white background, green as accent (not everywhere)
PAGE_BG = "#f7faf6"
CARD_BG = "#f1f8ef"
BORDER = "#d7e8d2"
GREEN = "#3f7a34"        # deeper green for legibility on white (the poster's pale
                          # lime only works on a dark background)
GREEN_DIM = "#6b8a6b"
TEXT = "#293a29"
TEXT_BRIGHT = "#1c3a17"

plt.rcParams.update({
    "figure.facecolor": "white",
    "axes.facecolor": "white",
    "axes.edgecolor": BORDER,
    "axes.labelcolor": TEXT,
    "text.color": TEXT,
    "xtick.color": GREEN_DIM,
    "ytick.color": GREEN_DIM,
    "grid.color": BORDER,
    "font.family": "monospace",
    "legend.facecolor": "white",
    "legend.edgecolor": BORDER,
    "legend.labelcolor": TEXT,
})

# Kept identical to plate_report.py's STYLE block for a consistent look
# across both report types -- RNATOR brand on white, banner image header.
STYLE = f"""
* {{ margin: 0; padding: 0; box-sizing: border-box; }}
body {{
    font-family: 'Courier New', Consolas, Monaco, monospace;
    line-height: 1.6; color: {TEXT};
    background: {PAGE_BG};
    padding: 20px;
}}
.container {{ max-width: 1400px; margin: 0 auto; background: white; border-radius: 12px;
             border: 1px solid {BORDER}; overflow: hidden; box-shadow: 0 2px 12px rgba(63,122,52,0.08); }}
header {{ background: white; padding: 32px 40px 24px; text-align: center; border-bottom: 1px solid {BORDER}; }}
header img.banner {{ max-width: 100%; width: 560px; image-rendering: pixelated; }}
header p.subtitle {{ font-size: 1.1em; color: {TEXT}; margin-top: 16px; }}
.content {{ padding: 40px; }}
section {{ margin-bottom: 50px; }}
h2 {{ font-size: 1.3em; color: {GREEN}; margin-bottom: 20px; text-transform: uppercase; letter-spacing: 2px;
     border-bottom: 2px solid {BORDER}; padding-bottom: 10px; }}
h3 {{ font-size: 0.95em; color: {GREEN_DIM}; text-transform: uppercase; letter-spacing: 1.5px;
     margin-top: 20px; margin-bottom: 15px; }}
.summary-grid {{ display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
                 gap: 16px; margin-bottom: 10px; }}
.summary-card {{ background: {CARD_BG}; border: 1px solid {BORDER}; border-radius: 10px; padding: 20px; }}
.summary-card .label {{ font-size: 0.72em; color: {GREEN_DIM}; text-transform: uppercase;
                        letter-spacing: 1.5px; margin-bottom: 8px; }}
.summary-card .value {{ font-size: 1.7em; font-weight: bold; color: {TEXT_BRIGHT}; }}
.figure {{ margin: 25px 0; text-align: center; }}
img {{ max-width: 100%; border-radius: 8px; border: 1px solid {BORDER}; }}
table.tbl {{ border-collapse: collapse; margin-bottom: 2em; width: 100%; font-size: 0.9em; }}
table.tbl td, table.tbl th {{ padding: 8px 12px; border-bottom: 1px solid {BORDER}; text-align: left; color: {TEXT}; }}
table.tbl th {{ background: {CARD_BG}; color: {GREEN}; text-transform: uppercase;
               letter-spacing: 1px; font-weight: 600; font-size: 0.82em; }}
table.tbl tr:hover {{ background: rgba(63,122,52,0.04); }}
p.note {{ color: {GREEN_DIM}; font-style: italic; }}
footer {{ border-top: 1px dashed {BORDER}; padding: 20px 40px; display: flex; justify-content: space-between;
         color: {GREEN_DIM}; font-size: 0.8em; text-transform: uppercase; letter-spacing: 1px; }}
"""


def fig_to_base64(fig):
    buf = io.BytesIO()
    fig.savefig(buf, format="png", bbox_inches="tight", dpi=110)
    plt.close(fig)
    return base64.b64encode(buf.getvalue()).decode("utf-8")


def compute_pca(adata, n_comps=10):
    if adata.n_obs < 3 or adata.n_vars < 3:
        return None
    ad2 = adata.copy()
    sc.pp.normalize_total(ad2, target_sum=1e4)
    sc.pp.log1p(ad2)
    n_comps = max(2, min(n_comps, ad2.n_obs - 1, ad2.n_vars - 1))
    sc.pp.pca(ad2, n_comps=n_comps)
    return ad2


def render_pca_plot(ad2, color_col, title):
    xs = ad2.obsm["X_pca"][:, 0]
    ys = ad2.obsm["X_pca"][:, 1]
    var_ratio = ad2.uns["pca"]["variance_ratio"]

    fig, ax = plt.subplots(figsize=(8, 6))
    categories = ad2.obs[color_col].astype(str)
    uniq = sorted(categories.unique())
    cmap = plt.cm.tab10 if len(uniq) <= 10 else plt.cm.tab20
    for i, cat in enumerate(uniq):
        mask = (categories == cat).values
        ax.scatter(xs[mask], ys[mask], label=cat, s=90, color=cmap(i % cmap.N),
                   edgecolor="white", linewidth=0.6, alpha=0.9)
    ax.set_xlabel(f"PC1 ({var_ratio[0]*100:.1f}% variance)")
    ax.set_ylabel(f"PC2 ({var_ratio[1]*100:.1f}% variance)")
    ax.set_title(title)
    ax.legend(bbox_to_anchor=(1.02, 1), loc="upper left", fontsize=8, title=color_col)
    ax.grid(alpha=0.2)
    return fig


def render_pca_variance(ad2, title):
    var_ratio = ad2.uns["pca"]["variance_ratio"]
    fig, ax = plt.subplots(figsize=(7, 4))
    ax.bar(range(1, len(var_ratio) + 1), var_ratio * 100, color=GREEN)
    ax.set_xlabel("Principal component")
    ax.set_ylabel("% variance explained")
    ax.set_title(title)
    ax.set_xticks(range(1, len(var_ratio) + 1))
    return fig


def summary_card(label, value):
    return f'<div class="summary-card"><div class="label">{label}</div><div class="value">{value}</div></div>'


def main():
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--h5ad", required=True, help="Merged per-project .h5ad from merge_project_h5ad.py")
    ap.add_argument("--project", required=True)
    ap.add_argument("--output", required=True)
    args = ap.parse_args()

    adata = ad.read_h5ad(args.h5ad)
    adata.obs["n_counts"] = adata.X.sum(axis=1).A1 if hasattr(adata.X, "A1") else adata.X.sum(axis=1)
    adata.obs["n_genes"] = (adata.X > 0).sum(axis=1).A1 if hasattr(adata.X, "A1") else (adata.X > 0).sum(axis=1)

    per_sample = adata.obs[["barcode", "sample_name", "library", "n_counts", "n_genes"]] \
        .sort_values("n_counts", ascending=False).reset_index(drop=True)

    fig1, ax1 = plt.subplots(figsize=(10, 4))
    ax1.bar(range(len(per_sample)), per_sample["n_counts"], color=GREEN)
    ax1.set_xlabel("Sample (ranked by UMI count)")
    ax1.set_ylabel("UMI count")
    ax1.set_title(f"{args.project}: UMI counts per sample (all plates)")
    umi_plot = fig_to_base64(fig1)

    n_libraries = adata.obs["library"].nunique()
    per_library = adata.obs.groupby("library", dropna=False)["n_counts"].agg(["count", "sum", "mean"])
    library_table = per_library.to_html(classes="tbl", border=0)
    sample_table = per_sample.to_html(classes="tbl", border=0, index=False)

    # PCA across every sample in the project, colored by which plate/library
    # it came from -- useful for spotting batch effects across plates.
    ad2 = compute_pca(adata)
    if ad2 is None:
        pca_html = "<p class=\"note\">Too few samples in this project for a meaningful PCA (need at least 3).</p>"
    else:
        pca_sections = []
        if ad2.obs["library"].nunique(dropna=True) > 1:
            fig = render_pca_plot(ad2, "library", f"{args.project}: PCA colored by plate/library")
            pca_sections.append(f'<div class="figure"><h3>Colored by plate</h3><img src="data:image/png;base64,{fig_to_base64(fig)}"></div>')
        else:
            fig = render_pca_plot(ad2, "sample_name", f"{args.project}: PCA by sample")
            pca_sections.append(f'<div class="figure"><img src="data:image/png;base64,{fig_to_base64(fig)}"></div>')
        fig_var = render_pca_variance(ad2, f"{args.project}: PCA variance explained")
        pca_sections.append(f'<div class="figure"><h3>Variance explained</h3><img src="data:image/png;base64,{fig_to_base64(fig_var)}"></div>')
        pca_html = "".join(pca_sections)

    mean_counts = int(per_sample["n_counts"].mean()) if len(per_sample) else 0
    mean_genes = int(per_sample["n_genes"].mean()) if len(per_sample) else 0
    cards = "".join([
        summary_card("Samples", adata.n_obs),
        summary_card("Plates", n_libraries),
        summary_card("Mean UMIs / sample", f"{mean_counts:,}"),
        summary_card("Mean genes / sample", f"{mean_genes:,}"),
    ])

    html = f"""<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>{args.project} -- Project QC Report</title>
<style>{STYLE}</style></head>
<body>
<div class="container">
<header>
<img class="banner" src="data:image/png;base64,{BANNER_B64}" alt="RNATOR">
<p class="subtitle">Project QC Report &middot; {args.project}</p>
</header>
<div class="content">

<section>
<div class="summary-grid">{cards}</div>
</section>

<section>
<h2>PCA</h2>
{pca_html}
</section>

<section>
<h2>UMI counts per sample</h2>
<div class="figure"><img src="data:image/png;base64,{umi_plot}"></div>
</section>

<section>
<h2>Per-plate summary</h2>
{library_table}
</section>

<section>
<h2>Per-sample detail</h2>
{sample_table}
</section>

</div>
<footer>
<span>RNATOR &middot; NGS Core</span>
<span>quick &amp; dirty bulk RNA-seq QC_</span>
</footer>
</div>
</body></html>"""

    with open(args.output, "w") as fh:
        fh.write(html)
    print(f"Wrote {args.output}")


if __name__ == "__main__":
    main()
